@import url('https://fonts.googleapis.com/css2?family=Work+Sans&display=swap');
@import url('https://fonts.googleapis.com/css2?family=Xanh+Mono&display=swap');

.page__main {
  padding: 1em 4em;
  background: none;
}
.theme-fandomdesktop-light, .theme-fandomdesktop-dark {
    --fandom-global-nav-background-color: var(--theme-page-accent-mix-color);
    --fandom-global-nav-link-color: var(--theme-community-header-color);
    --fandom-global-nav-icon-color: var(--theme-community-header-color--hover);
    --fandom-global-nav-icon-border-color: var(--theme-community-header-color--hover);
    --fandom-global-nav-bottom-icon-color: var(--theme-community-header-color--hover);
}
.main-container {
  background: linear-gradient(var(--theme-page-accent-mix-color) 0.7%, var(--theme-page-background-color) 2% 30%, var(--theme-page-background-color--secondary) 70%);
}
.page {
  Font-family: 'Work Sans', Sans-serif;
}
.page-content {
  text-align: justify;
}
.theme-fandomdesktop-light {
    --shadow: #d9d5d2;
}
.theme-fandomdesktop-dark {
    --shadow: #191512;
}
h1 {
    background: linear-gradient(370deg, var(--theme-page-background-color--secondary), transparent);
}
.page-content h1, .page-content h2, .page-content h3 {
  font-family: 'Xanh Mono', Serif;
}
.customhead {
  border-left: 2px solid var(--theme-border-color);
  font-size: 25px;
  padding-left: 15px;
  display: inline-block;
  margin: 0.3em;
  font-family: 'Xanh Mono', Serif;
  border-bottom: 2px groove var(--theme-link-color);
  font-weight: bold;
}
.cheadbg {
    background: linear-gradient(370deg, var(--theme-page-background-color), transparent);
    margin: 0.9em 0;
}
.theme-fandomdesktop-dark .fandom-community-header,
.theme-fandomdesktop-light .fandom-community-header {
    padding: 1em 2em;
    font-family: 'Xanh Mono', Serif;
}
.parent {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    grid-template-rows: repeat(2, 1fr);
    gap: 8px;
}
.t {
    will-change: transform;
    transition-duration: 0.5s;
}
.t:hover {
    transform: scale(105%);
}
.div1 {
    grid-row: span 2 / span 2;
    grid-column-start: 2;
    grid-row-start: 1;
    background-image: url('https://static.wikia.nocookie.net/backrooms/images/c/c1/Level_450.1_2_noai.png/revision/latest?cb=20260304064417');
    filter: contrast(70%);
    color: #110907;
    text-shadow: -2px -2px 0 #ccbbb7, 2px -2px 0 #ccbbb7, -2px  2px 0 #ccbbb7, 2px  2px 0 #ccbbb7;
    background-size: cover;
    will-change: transform;
    transition-duration: 0.5s;
}
.div1:hover {
    transform: scale(105%);
}
.div2 {
    grid-column-start: 3;
    grid-row-start: 1;
}

.div3 {
    grid-column-start: 3;
    grid-row-start: 2;
}

.div4 {
    grid-column-start: 1;
    grid-row-start: 1;
}

.div5 {
    grid-column-start: 1;
    grid-row-start: 2;
}

.line-top {
    display: block;
    height: 5px;
    background: linear-gradient(to right, transparent, transparent, var(--theme-border-color), var(--theme-page-text-color), var(--theme-border-color), transparent, transparent);
    border-bottom: 2px solid var(--theme-border-color);
    margin: 1em;
}

.line-bottom {
    display: block;
    height: 5px;
    background: linear-gradient(to right, transparent, transparent, var(--theme-border-color), var(--theme-page-text-color), var(--theme-border-color), transparent, transparent);
    border-top: 2px solid var(--theme-border-color);
    margin: 1em;
}

a {
  text-decoration: none;
  background-image: linear-gradient(to right, var(--theme-link-color), var(--theme-link-color), transparent);
  background-size: 0% 5px;
  background-repeat: no-repeat;
  background-position: left bottom;
  padding-bottom: 2px;
  transition: background-size 0.3s ease-out;
}

a:hover,
a:focus-visible {
  background-size: 100% 2px;
  text-decoration: none;
  font-weight: bold;
}
.cred {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  grid-template-rows: 1fr;
  grid-column-gap: 5px;
  grid-row-gap: 5px;
  text-align: left;
  border-bottom: 1px solid var(--theme-border-color);
}
.cred2 {
  padding: 15px 0;
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  grid-template-rows: 2fr;
  grid-column-gap: 5px;
  grid-row-gap: 5px;
  text-align: left;
  border-bottom: 1px solid var(--theme-border-color);
}
.bl1 { grid-area: 1 / 1 / 2 / 2; }
.bl2 { grid-area: 1 / 2 / 2 / 3; }

.bl3 { grid-area: 1 / 1 / 2 / 2; }
.bl4 { grid-area: 1 / 2 / 2 / 3; }

.global-footer, .global-footer__bottom {
	background: linear-gradient(#222222 70%, var(--theme-page-accent-mix-color) 90%);
    font-family: 'Work Sans';
}

.global-footer__section-header, .global-footer__bottom>div {
	color: #dedede;
}

.global-footer__link, .global-footer__link:active, .global-footer__link:focus, .global-footer__link:visited, .global-footer__bottom a, .global-footer__bottom a:visited {
	color: #a79c8b;
}

.global-footer__link:hover, .global-footer__bottom a:hover {
	color: #a79c8b;
}

.global-footer__bottom>div~div {
	border-top: solid 1px #dedede;
}
